#!/usr/bin/env bash
set -euo pipefail

cd /workspace/playwright

# Idempotency: if the vendored minimist already exists, skip.
if [ -f packages/playwright-core/src/tools/cli-client/minimist.ts ] \
   && grep -qF "should not be passed with '=value'" \
        packages/playwright-core/src/tools/cli-client/minimist.ts 2>/dev/null; then
  echo "Gold patch already applied, skipping."
  exit 0
fi

# Gold patch is base64-embedded to preserve trailing-whitespace context lines
# that text editors / heredoc rendering strip. The diff is byte-for-byte the
# upstream PR diff captured at task-build time.
PATCH_B64=''

echo "$PATCH_B64" | base64 -d | git apply --whitespace=nowarn -

echo "Patch applied successfully."
